export const uploadCaseFile = async (
  caseId: string,
  uploadCaseFileRequest: UploadCaseFileRequest,
  options?: RequestInit,
): Promise<CaseFile> => {
  const formData = new FormData();
  formData.append(`file`, uploadCaseFileRequest.file);
  formData.append(`sourceType`, uploadCaseFileRequest.sourceType);
  if (uploadCaseFileRequest.ocrText !== undefined) {
    formData.append(`ocrText`, uploadCaseFileRequest.ocrText);
  }
  if (uploadCaseFileRequest.pageCount !== undefined) {
    formData.append(`pageCount`, uploadCaseFileRequest.pageCount.toString());
  }

  return customFetch<CaseFile>(getUploadCaseFileUrl(caseId), {
    ...options,
    method: "POST",
    body: formData,
  });
};

