/**
 * Server-Sent Events stream of `AgentEvent` payloads for the run.

## Wire format

Each SSE message looks like:

```
id: 42
event: agent_event
data: {"idx":42,"type":"tool_call","subagent":"TimelineBuilder", ...}
```

- `id:` is the monotonic `eventIndex` of that event. Browsers and
  `react-native-sse` automatically resend it as the `Last-Event-ID`
  header on reconnect.
- `event:` is always `agent_event` for typed payloads (no separate
  channels).
- `data:` is one JSON-encoded `AgentEvent` per message.

## Resumption

- Pass `?since=N` (preferred) **or** the `Last-Event-ID: N` header
  (auto-set by SSE clients) to resume from event index `N+1`.
- The server replays persisted events from `run_events` synchronously
  before switching back to the live stream, so clients always see a
  monotonic `idx` with no gaps.
- Once the terminal `done` event has been delivered, the connection
  closes; reconnects after `done` immediately replay history and close
  again.

 * @summary R-11 Stream run events (SSE)
 */
export const getStreamRunEventsUrl = (
  runId: string,
  params?: StreamRunEventsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/v1/runs/${runId}/events?${stringifiedParams}`
    : `/api/v1/runs/${runId}/events`;
};

export const streamRunEvents = async (
  runId: string,
  params?: StreamRunEventsParams,
  options?: RequestInit,
): Promise<AgentEvent> => {
  return customFetch<AgentEvent>(getStreamRunEventsUrl(runId, params), {
    ...options,
    method: "GET",
  });
};

