/**
 * Multipart upload of one audio segment (typically 1-3s of opus
from MediaRecorder). The server transcribes, runs the
objection-rules lookup, and may publish an ObjectionEvent on
the session's SSE channel. The endpoint returns 202 immediately
— processing is fire-and-forget so the recorder never blocks.

 * @summary R-31 Upload one audio chunk
 */
export const getUploadCourtroomChunkUrl = (sessionId: string) => {
  return `/api/v1/courtroom/sessions/${sessionId}/audio`;
};

export const uploadCourtroomChunk = async (
  sessionId: string,
  uploadCourtroomChunkRequest: UploadCourtroomChunkRequest,
  options?: RequestInit,
): Promise<UploadCourtroomChunk202> => {
  const formData = new FormData();
  formData.append(`audio`, uploadCourtroomChunkRequest.audio);
  if (uploadCourtroomChunkRequest.language !== undefined) {
    formData.append(`language`, uploadCourtroomChunkRequest.language);
  }

  return customFetch<UploadCourtroomChunk202>(
    getUploadCourtroomChunkUrl(sessionId),
    {
      ...options,
      method: "POST",
      body: formData,
    },
  );
};

