/**
 * Server-Sent Events stream of `ObjectionEvent` payloads for the
session. Replays any buffered events past `?since=N`, then
attaches a live subscription. Events are ephemeral — buffered
in-memory and dropped at session end unless saved via R-33.

 * @summary R-32 Stream ObjectionEvents (SSE)
 */
export const getStreamCourtroomEventsUrl = (
  sessionId: string,
  params?: StreamCourtroomEventsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/v1/courtroom/sessions/${sessionId}/events?${stringifiedParams}`
    : `/api/v1/courtroom/sessions/${sessionId}/events`;
};

export const streamCourtroomEvents = async (
  sessionId: string,
  params?: StreamCourtroomEventsParams,
  options?: RequestInit,
): Promise<ObjectionEvent> => {
  return customFetch<ObjectionEvent>(
    getStreamCourtroomEventsUrl(sessionId, params),
    {
      ...options,
      method: "GET",
    },
  );
};

export const getStreamCourtroomEventsQueryKey = (
  sessionId: string,
  params?: StreamCourtroomEventsParams,
) => {
  return [
    `/api/v1/courtroom/sessions/${sessionId}/events`,
    ...(params ? [params] : []),
  ] as const;
};

